    line = strip_pid_prefix(line)
    for method in exec_methods:
        prefix = method + '("'
        if line.startswith(prefix):
            line = line[len(prefix):]
            parts = line.split('", ')
            if len(parts) > 1:
                return parts[0]
    return None


[GRAPH] src.exodus_bundler.input_parsing.extract_open_path
def extract_open_path(line):
    line = strip_pid_prefix(line)
    for prefix in ['openat(AT_FDCWD, "', 'open("']:
        if line.startswith(prefix):
            parts = line[len(prefix):].split('", ')
            if len(parts) != 2:
                continue
            if 'ENOENT' in parts[1]:
                continue
            if 'O_RDONLY' not in parts[1]:
                continue
            if 'O_DIRECTORY' in parts[1]:
                continue
            return parts[0]
    return None


