def extract_stat_path(line):
    line = strip_pid_prefix(line)
    prefix = 'stat("'
    if line.startswith(prefix):
        parts = line[len(prefix):].split('", ')
        if len(parts) == 2 and 'ENOENT' not in parts[1]:
            return parts[0]
    return None


